div.script:
document.querySelectorAll('.scrum_stage_option input[type="radio"]').forEach(function(radio) {
    radio.addEventListener('change', function() {
        // Remove selected class from all options
        document.querySelectorAll('.scrum_stage_option').forEach(function(opt) {
            opt.classList.remove('scrum_stage_option_selected');
        });
        // Add selected class to the clicked one
        this.closest('.scrum_stage_option').classList.add('scrum_stage_option_selected');
    });
});
